-- Move yellowing synthetic follow-up copy into governed data-layer templates.
-- Run after checking the three added column groups are absent; MySQL in this project
-- should not rely on ADD COLUMN IF NOT EXISTS.

ALTER TABLE `question_library_v5_real`
  ADD COLUMN `default_option_key` VARCHAR(128) NULL COMMENT '默认选项 key，用于 gate 类题默认选中' AFTER `why_this_question_cn`,
  ADD COLUMN `ui_variant` VARCHAR(64) NULL COMMENT '前端展示形态，例如 single_select_accordion' AFTER `default_option_key`,
  ADD COLUMN `render_mode` VARCHAR(64) NULL COMMENT 'static|data_template|runtime_fallback' AFTER `ui_variant`,
  ADD COLUMN `template_engine_rule_key` VARCHAR(128) NULL COMMENT '关联 question_generation_engine.engine_rule_key' AFTER `render_mode`;

ALTER TABLE `question_option_mapping_v5_real`
  ADD COLUMN `option_description_user_cn` TEXT NULL COMMENT '用户可见选项说明，允许 {{variable}} 模板变量' AFTER `answer_effect_cn`,
  ADD COLUMN `display_order` INT NULL COMMENT '选项展示顺序' AFTER `option_description_user_cn`,
  ADD COLUMN `is_default` TINYINT(1) NULL DEFAULT 0 COMMENT '是否为默认选项' AFTER `display_order`;

ALTER TABLE `question_generation_engine`
  ADD COLUMN `help_template_user_cn` TEXT NULL COMMENT '用户可见帮助模板' AFTER `template_user_cn`,
  ADD COLUMN `template_variables_json` TEXT NULL COMMENT '模板变量声明 JSON 文本' AFTER `help_template_user_cn`,
  ADD COLUMN `fallback_values_json` TEXT NULL COMMENT '变量缺失时的兜底值 JSON 文本' AFTER `template_variables_json`,
  ADD COLUMN `render_policy` VARCHAR(32) NULL COMMENT 'strict|fallback' AFTER `fallback_values_json`,
  ADD COLUMN `option_template_json` TEXT NULL COMMENT '动态选项模板声明 JSON 文本' AFTER `render_policy`;

